head.script:
	/**
	 * 화면 초기화에 필요한 로직을 수행한다.
	 */
	scwin.initScreen = function() {
		$(".pin").click(
				function() {
					comLib.confirm($p, utilLib.getMessage("SCM.INFO.00321"), "scwin.updatePriorNttYnConfirmCallback");
				});
		$(".del").click(function() {
			$("table.creat").removeClass("table-on");
			$("table.view").removeClass("table-on");
		});

		$(".modify").click(function() {
			dmaNttMt.set("rowStatus", "U");
			$("table.creat").removeClass("table-on");
			$("table.view").removeClass("table-on");
			$("table.creat").addClass("table-on");
			if(dmaNttMt.get( "nttClsCd1" ) != ""){
				sbxNttClsCd1.setValue( dmaNttMt.get( "nttClsCd1" ) );
			}
		});

		$p.$("#nttTrash").click(
			function() {
				comLib.confirm($p, utilLib.getMessage("SCM.INFO.00251"), "scwin.deleteNttLeft");
			}
		);

		$(".list li a").click(function() {
			$("table.creat").removeClass("table-on");
			$("table.view").addClass("table-on");
			$(".list > ul > li ").removeClass("active");
			$(this).parent().parent().addClass("active");
		});
		$(".nav-title-group .close").click(function() {
			$(".nav-board").removeClass("board-on");
			comLib.removeSrc();
		});

		$p.$("#btn_nttCreate").click(function() {
			scwin.btnAdd_onclick();
			$("table.mody").removeClass("table-on");
			$("table.creat").addClass("table-on");
			$("table.view").removeClass("table-on");
		});
		$p.$("#btnCancel").click(function() {
			if(dmaNttMt.get("rowStatus") == "C"){
				$("table.creat").removeClass("table-on");
				$("table.view").removeClass("table-on");
			}else{
				$("table.creat").removeClass("table-on");
				$("table.view").addClass("table-on");
			}
		});

	};

	/**
	 * 쓰기버튼클릭
	 * @param 저장할 데이터
	 * @return 
	 */ 
	scwin.btnAdd_onclick = function() {
		utilLib.clearDcObj(nttAtchfl.getWindow()._dltNttFile);
		var bbsId = dmaNttMt.get("bbsId");
		var sysDivCd = dmaNttMt.get("sysDivCd");

		utilLib.clearDcObj(dmaNttMt);

		dmaNttMt.set("rowStatus", "C");
		dmaNttMt.set("bbsId", bbsId);
		dmaNttMt.set("sysDivCd", sysDivCd);
		dmaNttMt.set("ntfStrtDe", utilLib.getCurrentDate());
		var nttMngData = $p.top().wframeLeft.getWindow().dltNttMng.getMatchedJSON( "bbsId" , bbsId );
		// 공지팝업인 경우 공지기간 default 1개월, 첨부파일 설명 써놓기
		if (nttMngData[0].bbsTyCd == "03") {
			var nttChildren = nttAtchfl.getAllChildren();
			for (var i = 0 ; i < nttChildren.length ; i++) {
				if (nttChildren[i].getPluginName() == "span") {
					nttChildren[i].render.innerHTML = "첨부파일 (1번파일 : 540px * 670px 사이즈의 팝업이미지, 이하파일 : 공지팝업에서 다운로드 될 참고자료)";
				}
			}
			dmaNttMt.set("ntfEndDe", utilLib.addToDay(utilLib.getCurrentDate(),'1'));
		} else {
			var nttChildren = nttAtchfl.getAllChildren();
			for (var i = 0 ; i < nttChildren.length ; i++) {
				if (nttChildren[i].getPluginName() == "span") {
					nttChildren[i].render.innerHTML = "첨부파일";
				}
			}
			dmaNttMt.set("ntfEndDe", utilLib.addToDay(utilLib.getCurrentDate(),'120'));		
		}
		dmaNttMt.set("priorNttYn", "N");
	};

	/**
	 * 저장버튼클릭
	 * @param 저장할 데이터
	 * @return
	 */
	scwin.btnSave_onclick = function() {
		// 입력값 셋팅
		if(ibxNttTit.getValue() == ""){
			comLib.alert($p,  utilLib.getMessage("SCM.INFO.00004", "제목 "));
			return false;
		}
		if(txaNttCtnt.getValue() == ""){
			comLib.alert($p,  utilLib.getMessage("SCM.INFO.00004", "내용 "));
			return false;
		}
		if (nttAtchfl.getWindow()._mpdNttMultiAtchFile.getFileCount() > 0) {
			nttAtchfl.getWindow()._mpdNttMultiAtchFile.startUpload();
		} else {
			comLib.confirm($p, utilLib.getMessage("SCM.INFO.00321"), "scwin.saveNttConfirmCallback");
		}
	};

	/**
	 * 저장처리
	 */
	scwin.saveNttConfirmCallback = function() {
		var requestData = {};
		requestData.data = dmaNttMt.getJSON();
		requestData.data1 = nttAtchfl.getWindow()._dltNttFile.getModifiedJSON();
		var option = {
			action : "sc/ntt/saveNtt.do",
			reqData : requestData,
			resData : dltNttList,
			success : "scwin.saveCallback" ,
			savedToken : true,
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	scwin.saveNttCallback = function(resBody) {
		comLib.NTT_NO = resBody.message.data;
		utilLib.clearDcObj(dltNttList);
		scwin.selectNttMng(txtNttNo.getValue() , parseInt(txtCnt.getValue())+1);
	}
	scwin.saveCallback = function(resBody) {
		comLib.NTT_NO = resBody.message.data;
		utilLib.clearDcObj(dltNttList);
		scwin.selectNttMng(txtNttNo.getValue() ,txtCnt.getValue());
	}

	/**
	 * 글제목클릭시
	 * @param 글번호
	 * @return
	 */
	scwin.selectNtt = function(nttNo) {
		$(".nttlist").removeClass("active");
		eval("nttLi_" + nttNo).classList.add("active");

		comLib.NTT_NO = nttNo;
		var dltNttListJson = dltNttList.getMatchedJSON("nttNo", comLib.NTT_NO, true, 0, dltNttList.getRowCount());

		$("table.creat").removeClass("table-on");
		$("table.view").addClass("table-on");

		utilLib.clearDcObj(dmaNttMt);
		dmaNttMt.set("rowStatus", "U");
		dmaNttMt.set("nttNo", dltNttListJson[0].nttNo);
		dmaNttMt.set("bbsId", dltNttListJson[0].bbsId);
		dmaNttMt.set("sysDivCd", dltNttListJson[0].sysDivCd);
		dmaNttMt.set("ctgryId", dltNttListJson[0].ctgryId);
		dmaNttMt.set("ntceLocgovCd", dltNttListJson[0].ntceLocgovCd);
		dmaNttMt.set("nttClsCd1", dltNttListJson[0].nttClsCd1);
		dmaNttMt.set("nttClsCd2", dltNttListJson[0].nttClsCd2);
		dmaNttMt.set("nttStatCd", dltNttListJson[0].nttStatCd);
		dmaNttMt.set("nttTit", dltNttListJson[0].nttTit);
		dmaNttMt.set("nttCtnt", dltNttListJson[0].nttCtnt);
		dmaNttMt.set("nttPwdno", dltNttListJson[0].nttPwdno);
		dmaNttMt.set("nttRdcnt", dltNttListJson[0].nttRdcnt);
		dmaNttMt.set("nttNtfFnctYn", dltNttListJson[0].nttNtfFnctYn);
		dmaNttMt.set("ntfStrtDe", dltNttListJson[0].ntfStrtDe);
		dmaNttMt.set("ntfEndDe", dltNttListJson[0].ntfEndDe);
		dmaNttMt.set("answerYn", dltNttListJson[0].answerYn);
		dmaNttMt.set("priorNttYn", dltNttListJson[0].priorNttYn);
		dmaNttMt.set("atchflId", dltNttListJson[0].atchflId);
		dmaNttMt.set("useYn", dltNttListJson[0].useYn);
		dmaNttMt.set("sortOrdr", dltNttListJson[0].sortOrdr);
		dmaNttMt.set("lastUpdtDt", dltNttListJson[0].frstRegistDt);

		scwin.updateNttRdcnt();

		$p.$("#nttPin").removeClass("pin-on");
		if (dltNttListJson[0].priorNttYn == "Y") {
			$p.$("#nttPin").toggleClass("pin-on");
		}

		if(dltNttListJson[0].frstRgstrId != comLib.getUsrId()){
			nttViewGroup.hide();
		}else{
			nttViewGroup.show("inline-block");
		}

		boardUsr.setLabel(dltNttListJson[0].korname + " / " + dltNttListJson[0].dept + " / " + dltNttListJson[0].posit);

		var nttMngData = $p.top().wframeLeft.getWindow().dltNttMng.getMatchedJSON( "bbsId" , dltNttListJson[0].bbsId );
		// 공지일을 사용하는 경우 공지기간을 표시
		if (nttMngData[0].bbsStatCd == "01") {
			txtNtcePd.setLabel("공지기간 : " + utilLib.makeDateFormat(dltNttListJson[0].ntfStrtDe, "-") + " ~ " + utilLib.makeDateFormat(dltNttListJson[0].ntfEndDe, "-"));
		} else {
			txtNtcePd.setLabel("");
		}

		viewFile.render.innerHTML = "";
		utilLib.clearDcObj(nttAtchfl.getWindow()._dltNttFile);
		comLib.NTT_NO = "";
		if (dltNttListJson[0].atchflId != null && dltNttListJson[0].atchflId != "") {
			var requestData = {};
			requestData.dmaFileBasic = {
				atchflId : dltNttListJson[0].atchflId
			};
			var option = {
				action : "sc/file/fileList.do",
				reqData : requestData,
				resData : nttAtchfl.getWindow()._dltNttFile,
				success : "scwin.searchNttMtCallback",
				isShowMeg : false
			};
			ajaxLib.executeAjax($p, option);
		} else {
			nttAtchfl.getWindow()._dltNttFile.deleteRow(0);
		}

	}

	/**
	 * 상세 첨부 콜백 함수
	 * @param
	 * @return
	 */
	scwin.searchNttMtCallback = function(resBody) {
		if (resBody.message.code == 'success') {
			if (nttAtchfl.getWindow()._dltNttFile.getRowCount() > 0) {
				var str = [];
				for (var i = 0; i < nttAtchfl.getWindow()._dltNttFile.getRowCount(); i++) {
					str.push("<a href=\"javascript:" + comLib.getFrameId($p) + "scwin.fileDownload('" + nttAtchfl.getWindow()._dltNttFile.getCellData(i, "atchflId") + "','" + nttAtchfl.getWindow()._dltNttFile.getCellData(i, "fileSeq") + "');\" class='w2anchor2 '>");
					str.push(nttAtchfl.getWindow()._dltNttFile.getCellData(i, "orginlFileNm"));
					str.push("</a>");
				}
				viewFile.render.innerHTML = str.join("");
			} else {
				viewFile.render.innerHTML = "";
			}
		} else {
			alert("fail");
		}

	};

	//scwin.saveCallback
	//저장 후 게시물 목록
	scwin.selectNttMng = function(bbsId , cnt) {
		$("table.creat").removeClass("table-on");
		$("table.view").removeClass("table-on");

		var dltNttMngJson =  $p.top().wframeLeft.getWindow().dltNttMng.getMatchedJSON( "bbsId" , bbsId , true , 0 , $p.top().wframeLeft.getWindow().dltNttMng.getRowCount() );

		if(dltNttMngJson.length > 0){
			var nttTit = "";
			var korname = "";

			if (sbxSearchTyCd.getValue() == "01") {
				nttTit = inputNttSearch.getValue();
			}
			if (sbxSearchTyCd.getValue() == "02") {
				korname = inputNttSearch.getValue();
			}
				nttID = dltNttMngJson[0].bbsId;
				dmaNttMt.set( "bbsId" , dltNttMngJson[0].bbsId );
				dmaNttMt.set( "sysDivCd" , dltNttMngJson[0].sysDivCd);

				var requestData = {};

				if(cnt < comLib.PAGE_SIZE){
					cnt = comLib.PAGE_SIZE;
				}
				requestData.data = {bbsId:dltNttMngJson[0].bbsId ,"nttTit" : nttTit,"korname" : korname, rnum:0 , totalCount : cnt - comLib.PAGE_SIZE, pageSize : comLib.PAGE_SIZE};
				var option = {action : "sc/ntt/retrieveNtt.do"
								, reqData : requestData
								, resData : ""
				 				, success : "comLib.selectNttMngCallback"
								, isShowMeg : false
							};
				ajaxLib.executeAjax($p, option);
		}
	};

//중요 여부 업데이트
	scwin.updatePriorNttYnConfirmCallback = function() {
		$p.$("#nttPin").toggleClass("pin-on");
		if (dmaNttMt.get("priorNttYn") == "Y") {
			dmaNttMt.set("priorNttYn", "N");
		} else {
			dmaNttMt.set("priorNttYn", "Y");
		}
		var requestData = {};
		requestData.dmaNttMt = dmaNttMt.getJSON();
		var option = {
			action : "sc/ntt/updatePriorNttYn.do",
			reqData : requestData,
			success : "scwin.saveCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	//조회수 업데이트
	scwin.updateNttRdcnt = function() {
		var requestData = {};
		requestData.dmaNttMt = dmaNttMt.getJSON();

		var option = {
			action : "sc/ntt/updateNttRdcnt.do",
			reqData : requestData,
			success : "",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	}

//삭제 클릭시 
	scwin.deleteNttLeft = function() {
		for (var i = 0; i < nttAtchfl.getWindow()._dltNttFile.getRowCount(); i++) {
			nttAtchfl.getWindow()._dltNttFile.deleteRow(i);
		}
		dmaNttMt.set("rowStatus", "D");
		var requestData = {};
		requestData.data = dmaNttMt.getJSON();
		requestData.data1 = nttAtchfl.getWindow()._dltNttFile.getAllJSON();

		var option = {
			action : "sc/ntt/saveNtt.do",
			reqData : requestData,
			success : "scwin.deleteCallback",
			savedToken : true,
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

//삭제후 콜백
	scwin.deleteCallback = function() {
		comLib.NTT_NO = "";
		$("table.creat").removeClass("table-on");
		$("table.view").removeClass("table-on");

		//삭제후 목록조회
		comLib.selectNttMng(txtNttNo.getValue() , 0);

	}

	//돋보기 클릭
	scwin.searchBtn_onclick = function() {
		comLib.selectNttMng(txtNttNo.getValue() , 0);
	};

	/**
	 * 첨부파일 다운로드
	 * @param event
	 * @return첨부파일
	 */

	scwin.fileDownload = function(atchflId, fileSeq) {
		if (atchflId != null && atchflId != '') {
			var dmaTest = {
				"atchflId" : atchflId,
				"fileSeq" : fileSeq
			};
			var xmlValue = JSON.stringify(dmaTest);
			// $w.download("/sc/file/downloadAtchFileOne.do", xmlValue, "get");
			comLib.downloadAtchfl("/sc/file/downloadAtchFileOne.do", xmlValue, "get");
		}
	};

//신규버튼 클릭시
	scwin.btnAddList_onclick = function() {
		comLib.selectNttMng(txtNttNo.getValue() ,txtCnt.getValue());
	};
